import "package:flutter/material.dart"; import "../../ui/nios_ui.dart"; class FloatingScrollButton extends StatefulWidget { final ScrollController scrollController; final VoidCallback? onPressed; const FloatingScrollButton({super.key, required this.scrollController, this.onPressed}); @override State<FloatingScrollButton> createState() => _FloatingScrollButtonState(); } class _FloatingScrollButtonState extends State<FloatingScrollButton> { bool _showButton = false; int _unreadCount = 0; @override void initState() { super.initState(); widget.scrollController.addListener(_onScroll); } @override void dispose() { widget.scrollController.removeListener(_onScroll); super.dispose(); } void _onScroll() { final show = widget.scrollController.offset > 200; if (show != _showButton) { setState(() => _showButton = show); } } void _scrollToBottom() { widget.scrollController.animateTo(0, duration: const Duration(milliseconds: 300), curve: Curves.easeOut); widget.onPressed?.call(); } @override Widget build(BuildContext context) { return AnimatedOpacity(opacity: _showButton ? 1.0 : 0.0, duration: const Duration(milliseconds: 200), child: IgnorePointer(ignoring: !_showButton, child: GestureDetector(onTap: _scrollToBottom, child: Container(padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8), decoration: BoxDecoration(color: NiosPalette.surface, borderRadius: BorderRadius.circular(20), boxShadow: [BoxShadow(color: Colors.black.withValues(alpha: 0.2), blurRadius: 8, offset: const Offset(0, 2))]), child: Row(mainAxisSize: MainAxisSize.min, children: [Icon(Icons.keyboard_arrow_down, color: NiosPalette.accent, size: 20), if (_unreadCount > 0) ...[const SizedBox(width: 4), Container(padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2), decoration: BoxDecoration(color: NiosPalette.accent, borderRadius: BorderRadius.circular(10)), child: Text("$_unreadCount", style: const TextStyle(color: Colors.white, fontSize: 12, fontWeight: FontWeight.w600)))]]))))); } void updateUnreadCount(int count) { setState(() => _unreadCount = count); } }
